  6→package kotlinx.datetime.internal.format.formatter
  7→
  8→import kotlinx.datetime.internal.DecimalFraction
  9→import kotlinx.datetime.internal.POWERS_OF_TEN
 10→import kotlin.math.absoluteValue
 11→
 12→internal class ConstantStringFormatterStructure<in T>(
 13→    private val string: String,
 14→): FormatterStructure<T> {
 15→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
 16→        builder.append(string)
 17→    }
 18→}
 19→
 20→internal class UnsignedIntFormatterStructure<in T>(
 21→    private val number: (T) -> Int,
 22→    private val zeroPadding: Int,
 23→): FormatterStructure<T> {
 24→
 25→    init {
 26→        require(zeroPadding >= 0) { "The minimum number of digits ($zeroPadding) is negative" }
 27→        require(zeroPadding <= 9) { "The minimum number of digits ($zeroPadding) exceeds the length of an Int" }
 28→    }
 29→
 30→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
 31→        val num = number(obj)
 32→        val numberStr = num.toString()
 33→        repeat(zeroPadding - numberStr.length) { builder.append('0') }
 34→        builder.append(numberStr)
 35→    }
 36→}
 37→
 38→internal class SignedIntFormatterStructure<in T>(
 39→    private val number: (T) -> Int,
 40→    private val zeroPadding: Int,
 41→    private val outputPlusOnExceededWidth: Int?,
 42→): FormatterStructure<T> {
 43→
 44→    init {
 45→        require(zeroPadding >= 0) { "The minimum number of digits ($zeroPadding) is negative" }
 46→        require(zeroPadding <= 9) { "The minimum number of digits ($zeroPadding) exceeds the length of an Int" }
 47→    }
 48→
 49→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
 50→        val innerBuilder = StringBuilder()
 51→        val number = number(obj).let { if (minusNotRequired && it < 0) -it else it }
 52→        if (outputPlusOnExceededWidth != null && number >= POWERS_OF_TEN[outputPlusOnExceededWidth]) {
 53→            innerBuilder.append('+')
 54→        }
 55→        if (number.absoluteValue < POWERS_OF_TEN[zeroPadding - 1]) {
 56→            // needs padding
 57→            if (number >= 0) {
 58→                innerBuilder.append((number + POWERS_OF_TEN[zeroPadding])).deleteAt(0)
 59→            } else {
 60→                innerBuilder.append((number - POWERS_OF_TEN[zeroPadding])).deleteAt(1)
 61→            }
 62→        } else {
 63→            innerBuilder.append(number)
 64→        }
 65→        builder.append(innerBuilder)
 66→    }
 67→}
 68→
 69→internal class DecimalFractionFormatterStructure<in T>(
 70→    private val number: (T) -> DecimalFraction,
 71→    private val minDigits: Int,
 72→    private val maxDigits: Int,
 73→    private val zerosToAdd: List<Int>,
 74→): FormatterStructure<T> {
 75→
 76→    init {
 77→        require(minDigits in 1..9) {
 78→            "The minimum number of digits ($minDigits) is not in range 1..9"
 79→        }
 80→        require(maxDigits in minDigits..9) {
 81→            "The maximum number of digits ($maxDigits) is not in range $minDigits..9"
 82→        }
 83→    }
 84→
 85→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
 86→        val number = number(obj)
 87→        // round the number to `maxDigits` significant figures
 88→        val numberWithRequiredPrecision = number.fractionalPartWithNDigits(maxDigits)
 89→        // we strip away trailing zeros while we can
 90→        var zerosToStrip = 0
 91→        while (maxDigits > minDigits + zerosToStrip && numberWithRequiredPrecision % POWERS_OF_TEN[zerosToStrip + 1] == 0) {
 92→            ++zerosToStrip
