fun main() {
    // Test the error message improvement
    val zone = TimeZone.of("America/New_York")
    val readableFormat = DateTimeComponents.Format {
        year()
        char('-')
        monthNumber()
        char('-')
        dayOfMonth()
        char(' ')
        hour()
        char(':')
        minute()
        char(':')
        second()
        alternativeParsing({}) {
            char(' ')
        }
        alternativeParsing(
            { timeZoneId() },
            { offset(UtcOffset.Formats.ISO) }
        ) {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
            optional {
                char(':')
                offsetSecondsOfMinute()
            }
        }
    }

    val instant = Clock.System.now()

    // Test 1: Missing timeZoneId and missing offset - should trigger better error
    println("Test 1: Simulating user code that may have an issue...")
    try {
        val result = readableFormat.format {
            setDateTime(instant.toLocalDateTime(zone))
            // timeZoneId = zone.id  // Missing - should use offset branch
            // setOffset(...) // Missing - should trigger error
        }
        println("Result: $result")
    } catch (e: Exception) {
        println("Error message: ${e.message}")
        println("Error type: ${e.javaClass.simpleName}")
        // Check if error message is user-friendly
        if (e.message?.contains("offsetHours") == true || e.message?.contains("offsetMinutesOfHour") == true) {
            println("✓ Error message uses user-facing names!")
        } else if (e.message?.contains("totalHoursAbs") == true || e.message?.contains("minutesOfHour") == true) {
            println("✗ Error message still uses internal names!")
        } else {
            println("? Error message is different")
        }
    }

    // Test 2: Proper usage - should work
    println("\nTest 2: Proper usage with timeZoneId...")
    try {
        val result = readableFormat.format {
            setDateTime(instant.toLocalDateTime(zone))
            timeZoneId = zone.id
        }
        println("Result: $result")
    } catch (e: Exception) {
        println("Error: ${e.message}")
    }

    // Test 3: Proper usage with offset - should work
    println("\nTest 3: Proper usage with offset...")
    try {
        val result = readableFormat.format {
            setDateTime(instant.toLocalDateTime(zone))
            setOffset(zone.rules.offsetAt(instant))
        }
        println("Result: $result")
    } catch (e: Exception) {
        println("Error: ${e.message}")
    }

    // Test 4: Simple format with just offset hours
    println("\nTest 4: Simple offset format...")
    val simpleFormat = DateTimeComponents.Format {
        offsetHours()
    }
    try {
        val result = simpleFormat.format {
            // Missing offset - should trigger error
        }
        println("Result: $result")
    } catch (e: Exception) {
        println("Error message: ${e.message}")
        if (e.message?.contains("offsetHours") == true) {
            println("✓ Error message uses 'offsetHours' (user-facing name)")
        } else if (e.message?.contains("totalHoursAbs") == true) {
            println("✗ Error message uses 'totalHoursAbs' (internal name)")
        }
    }

    // Test 5: Simple format with offset hours and minutes
    println("\nTest 5: Offset with hours and minutes...")
    val offsetFormat = DateTimeComponents.Format {
        offsetHours()
        char(':')
        offsetMinutesOfHour()
    }
    try {
        val result = offsetFormat.format {
            // Missing offset fields - should trigger error
        }
        println("Result: $result")
    } catch (e: Exception) {
        println("Error message: ${e.message}")
        val message = e.message ?: ""
        var hasCorrectNames = false
        var hasOldNames = false
        if (message.contains("offsetHours") || message.contains("offsetMinutesOfHour")) {
            hasCorrectNames = true
        }
        if (message.contains("totalHoursAbs") || message.contains("minutesOfHour")) {
            hasOldNames = true
        }
        if (hasCorrectNames && !hasOldNames) {
            println("✓ Error message uses all correct user-facing names")
        } else if (hasOldNames) {
            println("✗ Error message still uses internal names")
        } else {
            println("? Error message is different")
        }
    }
}"}

