package kotlinx.datetime.format

import kotlinx.datetime.*
import kotlin.test.*

class ErrorMessageTest {
    @Test
    fun offsetErrorMessageUsesUserFacingNames() {
        // Test that when formatting with missing offset fields, the error message
        // uses user-facing names like "offsetHours" instead of internal names like "totalHoursAbs"

        val format = DateTimeComponents.Format {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
        }

        val e = assertFailsWith<IllegalStateException> {
            format.format {
                // Not setting any offset fields - should trigger error
            }
        }

        val message = e.message ?: ""
        assertTrue(
            message.contains("offsetHours") || message.contains("offsetMinutesOfHour"),
            "Error message should mention user-facing field names, but got: $message"
        )
        assertFalse(
            message.contains("totalHoursAbs") || message.contains("minutesOfHour"),
            "Error message should not mention internal field names, but got: $message"
        )
    }

    @Test
    fun offsetSecondsErrorMessageUsesUserFacingNames() {
        val format = DateTimeComponents.Format {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
            char(':')
            offsetSecondsOfMinute()
        }

        val e = assertFailsWith<IllegalStateException> {
            format.format {
                // Not setting any offset fields
            }
        }

        val message = e.message ?: ""
        assertTrue(
            message.contains("offsetHours") || message.contains("offsetMinutesOfHour") || message.contains("offsetSecondsOfMinute"),
            "Error message should mention user-facing field names, but got: $message"
        )
        assertFalse(
            message.contains("totalHoursAbs") || message.contains("minutesOfHour") || message.contains("secondsOfMinute"),
            "Error message should not mention internal field names, but got: $message"
        )
    }

    @Test
    fun timeZoneIdErrorMessage() {
        val format = DateTimeComponents.Format {
            timeZoneId()
        }

        val e = assertFailsWith<IllegalStateException> {
            format.format {
                // Not setting timeZoneId
            }
        }

        val message = e.message ?: ""
        assertTrue(
            message.contains("not set"),
            "Error message should indicate field is not set, but got: $message"
        )
    }
}"}

