{"file_path":"/project/test_instant_parse_consistency.kt","content":"// Test to verify Instant.parse consistency across platforms
package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlin.test.Test
import kotlin.test.assertFailsWith
import kotlin.time.Duration.Companion.seconds

@Suppress("DEPRECATION")
class InstantParseConsistencyTest {

    /**
     * Test that Instant.parse rejects omitting seconds (without seconds: "2024-03-19T17:50Z")
     * 
     * According to the documentation for DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET:
     * "This format differs from LocalTime.Formats.ISO in its time part in that
     * specifying the seconds is not optional."
     * 
     * Therefore, parsing "2024-03-19T17:50Z" should fail on ALL platforms consistently.
     */
    @Test
    fun parseWithoutSecondsFails() {
        // This should fail because seconds are required
        assertFailsWith<DateTimeFormatException> {
            Instant.parse("2024-03-19T17:50Z")
        }
    }

    /**
     * Test that Instant.parse accepts times with seconds (with seconds: "2024-03-19T17:50:30Z")
     */
    @Test
    fun parseWithSecondsSucceeds() {
        val instant = Instant.parse("2024-03-19T17:50:30Z")
        assertEquals(Instant.fromEpochSeconds(1710858630, 0), instant)
    }

    /**
     * Test that seconds with fractional parts work
     */
    @Test
    fun parseWithFractionalSecondsSucceeds() {
        val instant1 = Instant.parse("2024-03-19T17:50:30.123Z")
        val instant2 = Instant.parse("2024-03-19T17:50:30.123456789Z")
        // Both should parse successfully
        assertTrue(instant1 < instant2) // instant2 has more nanoseconds
    }

    /**
     * Test that offset variations work correctly
     */
    @Test
    fun parseWithDifferentOffsetsSucceeds() {
        val instantZ = Instant.parse("2024-03-19T17:50:30Z")
        val instantPlus = Instant.parse("2024-03-19T17:50:30+03:00")
        val instantMinus = Instant.parse("2024-03-19T14:50:30-03:00")

        // All these should represent the same moment in time
        assertEquals(instantZ, instantPlus)
        assertEquals(instantZ, instantMinus)
    }

    /**
     * Test that offset minutes can be optional (as per documentation)
     * 
     * From the ISO_DATE_TIME_OFFSET documentation:
     * "specifying the minutes is optional" for the UTC offset.
     */
    @Test
    fun parseWithOffsetWithoutMinutesSucceeds() {
        // This should work because offset minutes are optional
        val instant = Instant.parse("2024-03-19T17:50:30+03")
        val expected = Instant.parse("2024-03-19T14:50:30Z")

        assertEquals(expected, instant)
    }

    /**
     * Test round-trip: format an Instant and parse it back
     */
    @Test
    fun testFormatParseRoundTrip() {
        val original = Instant.fromEpochSeconds(1710858630, 500_000_000)
        val formatted = original.toString()
        val parsed = Instant.parse(formatted)

        // After formatting and parsing, we might lose some precision but the core instant should be the same
        // or very close (within nanoseconds)
        assertEquals(original.epochSeconds, parsed.epochSeconds)
        assertEquals(original.nanosecondsOfSecond, parsed.nanosecondsOfSecond)
    }
}"}

