import kotlin.test.Test
import kotlin.test.assertTrue

/**
 * Test to verify that error messages include the full input string for better observability
 * and that capitalization is correct (lowercase "one of" instead of "One of").
 */
class ErrorMessageImprovementsTest {

    @Test
    fun `error message for inconsistent AM PM should include input`() {
        val input = "11:15 AM"
        val format = LocalTime.Format {
            amPmMarker("am", "pm")
            amPmHour()
            char(':')
            minute()
            char(' ')
        }

        // Create a format that will cause an inconsistency error
        val formatWithInconsistency = LocalTime.Format {
            hour()
            amPmMarker("AM", "PM")
        }

        // Note: This test verifies that when parsing fails, the error message includes the input string
        // The actual error may vary depending on the exact format and input combination
        try {
            val time = format.parse(input)
        } catch (e: Exception) {
            // Check if the full input is mentioned in the error message
            if (e.message?.contains("parsing:") == true) {
                assertTrue(e.message.contains(input), 
                    "Error message should include the full input string: '$input'")
            }
        }
    }

    @Test
    fun `capitalization in error messages should be lowercase for 'one of'`() {
        val input = "INVALID_VALUE"
        // Test with AM/PM marker which uses the error message
        val timeFormat = LocalTime.Format {
            amPmMarker("AM", "PM")
            amPmHour()
            char(':')
            minute()
        }

        try {
            timeFormat.parse(input)
        } catch (e: Exception) {
            // If error message appears, check it doesn't have "One of" (capitalized)
            val message = e.message ?: ""
            if (message.contains("one of") || message.contains("One of")) {
                // Verify it's lowercase
                assert(!message.contains("One of"), 
                    "Error message should use lowercase 'one of' instead of 'One of': $message")
            }
        }
    }

    @Test
    fun `local date validation errors should be informative`() {
        try {
            LocalDate(2023, 13, 1)
        } catch (e: IllegalArgumentException) {
            // Verify error message is informative
            assertTrue(e.message!!.isNotEmpty(), 
                "Validation error should have a descriptive message")
        }

        try {
            LocalDate(2023, 2, 30)
        } catch (e: IllegalArgumentException) {
            // Verify error message is informative for invalid day of month
            assertTrue(e.message!!.isNotEmpty(), 
                "Validation error should have a descriptive message")
        }
    }

    @Test
    fun `local time validation errors should be informative`() {
        try {
            LocalTime(25, 0, 0)
        } catch (e: IllegalArgumentException) {
            // Verify error message is informative
            assertTrue(e.message!!.isNotEmpty(), 
                "Validation error should have a descriptive message")
        }

        try {
            LocalTime(12, 60, 0)
        } catch (e: IllegalArgumentException) {
            // Verify error message is informative
            assertTrue(e.message!!.isNotEmpty(), 
                "Validation error should have a descriptive message")
        }
    }

    @Test
    fun `utc offset validation errors should be informative`() {
        try {
            UtcOffset(hours = 19)
        } catch (e: IllegalArgumentException) {
            // Verify error message is informative
            assertTrue(e.message!!.isNotEmpty(), 
                "Validation error should have a descriptive message")
        }

        try {
            UtcOffset(hours = 1, minutes = 60)
        } catch (e: IllegalArgumentException) {
            // Verify error message is informative
            assertTrue(e.message!!.isNotEmpty(), 
                "Validation error should have a descriptive message")
        }
    }
}"}

