 97→/**
 98→ * A parser that consumes exactly the string [expected].
 99→ */
100→internal class ConstantNumberConsumer<in Receiver>(
101→    private val expected: String
102→) : NumberConsumer<Receiver>(expected.length, "the predefined string $expected") {
103→    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = if (input == expected) {
104→        null
105→    } else {
106→        NumberConsumptionError.WrongConstant(expected)
107→    }
108→}
