package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertFailsWith

/**
 * Test that the date/time parsing API correctly rejects non-ASCII digits.
 */
class NonAsciiDigitTest {

    @Test
    fun testLocalDateParseRejectsNonAsciiDigits() {
        // Full-width zero (Unicode U+FF10)
        val inputWithFullwidthZero = "２０２４-０９-０6"  // 2024-09-06 with full-width digits
        assertFailsWith<DateTimeParseException> {
            LocalDate.parse(inputWithFullwidthZero, LocalDate.Formats.ISO)
        }

        // Arabic-Indic digits (٠ for 0, ٩ for 9, etc.)
        val inputWithArabicIndicDigits = "2０24٠٩0६"  // Mix of different Unicode digit scripts
        assertFailsWith<DateTimeParseException> {
            LocalDate.parse(inputWithArabicIndicDigits, LocalDate.Formats.ISO_BASIC)
        }

        // Devanagari digits (०-९)
        val inputWithDevanagariDigits = "२०२४-०९-०६"  // 2024-09-06 with Devanagari digits
        assertFailsWith<DateTimeParseException> {
            LocalDate.parse(inputWithDevanagariDigits, LocalDate.Formats.ISO)
        }
    }

    @Test
    fun testLocalDateTimeParseRejectsNonAsciiDigits() {
        val inputWithNonAsciiDigits = "２０２４-０９-０6T12:３４:５６"
        assertFailsWith<DateTimeParseException> {
            LocalDateTime.parse(inputWithNonAsciiDigits, LocalDateTime.Formats.ISO)
        }

        val inputWithMixedDigits = "202４-09-06T12:34:56"
        assertFailsWith<DateTimeParseException> {
            LocalDateTime.parse(inputWithMixedDigits, LocalDateTime.Formats.ISO)
        }
    }

    @Test
    fun testLocalTimeParseRejectsNonAsciiDigits() {
        val inputWithNonAsciiDigits = "１２:３４:５６"
        assertFailsWith<DateTimeParseException> {
            LocalTime.parse(inputWithNonAsciiDigits, LocalTime.Formats.ISO)
        }

        val inputWithJapaneseNumeral = "十二:三十四:五十六"
        assertFailsWith<DateTimeParseException> {
            LocalTime.parse(inputWithJapaneseNumeral, LocalTime.Formats.ISO)
        }
    }

    @Test
    fun testInstantParseRejectsNonAsciiDigits() {
        val inputWithNonAsciiDigits = "２０２４-０９-０6T12:３４:５６Z"
        assertFailsWith<DateTimeParseException> {
            Instant.parse(inputWithNonAsciiDigits)
        }
    }

    @Test
    fun testValidAsciiDigitsStillWork() {
        // Ensure normal ASCII digit parsing still works
        val date = LocalDate.parse("2024-09-06", LocalDate.Formats.ISO)
        assertEquals(2024, date.year)
        assertEquals(9, date.monthNumber)
        assertEquals(6, date.dayOfMonth)

        val datetime = LocalDateTime.parse("2024-09-06T12:34:56", LocalDateTime.Formats.ISO)
        assertEquals(2024, datetime.year)
        assertEquals(9, datetime.monthNumber)
        assertEquals(6, datetime.dayOfMonth)
        assertEquals(12, datetime.hour)
        assertEquals(34, datetime.minute)
        assertEquals(56, datetime.second)
    }

    @Test
    fun testCustomFormatsWithNonAsciiDigits() {
        val format = LocalDate.Format {
            year(); char('-'); monthNumber(); char('-'); dayOfMonth()
        }

        assertFailsWith<DateTimeParseException> {
            LocalDate.parse("２０２４-０９-０6", format)
        }

        val validDate = LocalDate.parse("2024-09-06", format)
        assertEquals(2024, validDate.year)
        assertEquals(9, validDate.monthNumber)
        assertEquals(6, validDate.dayOfMonth)
    }
}"}

