 25→        if (startIndex + string.length > input.length)
 26→            return ParseResult.Error(startIndex) { "Unexpected end of input: yet to parse '$string'" }
 27→        for (i in string.indices) {
 28→            if (input[startIndex + i] != string[i]) return ParseResult.Error(startIndex) {
