 60→        }
 61→    }
 62→
 63→    private val whatThisExpects: String
 64→        get() {
 65→            val consumerLengths = consumers.map {
 66→                when (val length = it.length) {
 67→                    null -> "at least one digit"
 68→                    else -> "$length digits"
 69→                } + " for ${it.whatThisExpects}"
 70→            }
 71→            return if (isFlexible) {
 72→                "a number with at least $minLength digits: $consumerLengths"
 73→            } else {
